package main

import (
    "errors"
    "io/ioutil"
    "os"
    "path/filepath"
    "strconv"
)

// Compliant: Use application-specific directory with proper permissions
func saveConfigFileSecure(config []byte) error {
    // Create application-specific config directory
    configDir := "/var/lib/myapp"
    err := os.MkdirAll(configDir, 0755) // Only owner can write
    if err != nil {
        return err
    }

    configPath := filepath.Join(configDir, "config.json")
    return ioutil.WriteFile(configPath, config, 0644) // Owner write, group/world read
}

// Compliant: Use user-specific directories
func createLogFileSecure(logData string) error {
    // Use user-specific log directory
    logDir := "/var/log/myapp"
    err := os.MkdirAll(logDir, 0750) // Owner and group only
    if err != nil {
        return err
    }

    logPath := filepath.Join(logDir, "application.log")
    return ioutil.WriteFile(logPath, []byte(logData), 0640) // Restrictive permissions
}

// Compliant: Secure temporary file creation
func createSecureTempFile(data []byte) (string, error) {
    // Use ioutil.TempFile for secure temporary files
    tempFile, err := ioutil.TempFile("", "myapp_*.tmp")
    if err != nil {
        return "", err
    }
    defer tempFile.Close()

    // Write data
    _, err = tempFile.Write(data)
    if err != nil {
        os.Remove(tempFile.Name())
        return "", err
    }

    // Set restrictive permissions
    err = tempFile.Chmod(0600) // Owner only
    if err != nil {
        os.Remove(tempFile.Name())
        return "", err
    }

    return tempFile.Name(), nil
}

// Compliant: Proper user data storage with access controls
func saveUserDataSecure(userData []byte, userID string) error {
    // Validate userID
    if userID == "" || len(userID) > 32 {
        return errors.New("invalid user ID")
    }

    // Use application data directory
    baseDir := "/var/lib/myapp/users"
    err := os.MkdirAll(baseDir, 0755)
    if err != nil {
        return err
    }

    // Create user-specific subdirectory
    userDir := filepath.Join(baseDir, userID)
    err = os.MkdirAll(userDir, 0700) // User private directory
    if err != nil {
        return err
    }

    userFile := filepath.Join(userDir, "data.json")
    return ioutil.WriteFile(userFile, userData, 0600) // User-only access
}

// Compliant: Secure session storage
func storeSessionDataSecure(sessionID string, data []byte) error {
    // Validate session ID format
    if len(sessionID) != 32 {
        return errors.New("invalid session ID")
    }

    // Use application-specific session directory
    sessionDir := "/var/lib/myapp/sessions"
    err := os.MkdirAll(sessionDir, 0700) // Application private
    if err != nil {
        return err
    }

    sessionPath := filepath.Join(sessionDir, sessionID+".dat")
    return ioutil.WriteFile(sessionPath, data, 0600) // Highly restrictive
}

// Compliant: Runtime directory for current user
func createUserRuntimeFile(filename string, data []byte) error {
    // Use XDG runtime directory or similar
    runtimeDir := os.Getenv("XDG_RUNTIME_DIR")
    if runtimeDir == "" {
        // Fallback: create user-specific runtime directory
        uid := os.Getuid()
        runtimeDir = "/run/user/" + strconv.Itoa(uid)
    }

    // Ensure directory exists with proper permissions
    err := os.MkdirAll(runtimeDir, 0700)
    if err != nil {
        return err
    }

    filePath := filepath.Join(runtimeDir, filename)
    return ioutil.WriteFile(filePath, data, 0600)
}

// Compliant: Cross-platform temp directory with security
func createSecureTempDir() (string, error) {
    // Create a secure temporary directory
    tempDir, err := ioutil.TempDir("", "myapp_*")
    if err != nil {
        return "", err
    }

    // Set restrictive permissions
    err = os.Chmod(tempDir, 0700)
    if err != nil {
        os.RemoveAll(tempDir)
        return "", err
    }

    return tempDir, nil
}
